class TestReviewFindings2l:
    def test_missing_da_font_substitutes_honestly_and_reports(self, tmp_dir):
        # Review HIGH: /DA names /TiRo, /DR lacks it. The fallback must NOT
        # register Helvetica under the name TiRo (wrong face claimed, shared
        # /DR polluted for every field referencing it). It renders AND names
        # Helvetica, locally only, and the result reports the substitution.
        src = os.path.join(tmp_dir, "tiro.pdf")
        pdf = pikepdf.new()
        page = pdf.add_blank_page(page_size=(300, 300))
        helv = pdf.make_indirect(
            Dictionary(Type=Name.Font, Subtype=Name.Type1, BaseFont=Name.Helvetica, Encoding=Name.WinAnsiEncoding)
        )
        fld = pdf.make_indirect(
            Dictionary(
                Type=Name.Annot, Subtype=Name.Widget, Rect=[40, 200, 260, 224],
                T=pikepdf.String("styled"), FT=Name.Tx,
                DA=pikepdf.String("/TiRo 12 Tf 0 g"),
            )
        )
        page.obj["/Annots"] = pikepdf.Array([fld])
        pdf.Root["/AcroForm"] = pdf.make_indirect(
            Dictionary(Fields=pikepdf.Array([fld]), DR=Dictionary(Font=Dictionary(Helv=helv)))
        )
        pdf.save(src)
        pdf.close()

        out = os.path.join(tmp_dir, "out.pdf")
        r = fill_form_fields(src, out, {"styled": "Hello"})
        assert r["fonts_substituted"] == ["styled"]
        with pikepdf.open(out) as pdf2:
            widget = pdf2.pages[0].obj["/Annots"][0]
            ap = widget["/AP"]["/N"].read_bytes()
            assert b"/Helv " in ap and b"/TiRo" not in ap  # honest naming
            res_fonts = widget["/AP"]["/N"]["/Resources"]["/Font"]
            assert "/Helv" in res_fonts and "/TiRo" not in res_fonts
            # Shared /DR unpolluted: no fake TiRo entry anywhere.
            dr_fonts = pdf2.Root["/AcroForm"]["/DR"]["/Font"]
            assert "/TiRo" not in dr_fonts

    def test_all_encoding_problems_listed_together(self, tmp_dir):
        # Review: two non-WinAnsi values must BOTH appear in one error.
        out = os.path.join(tmp_dir, "nope.pdf")
        with pytest.raises(ValueError) as exc:
            fill_form_fields(
                PDFLIB_FORM, out,
                {"applicant.name": "日本語", "notes": "кириллица"},
            )
        msg = str(exc.value)
        assert "applicant.name" in msg and "notes" in msg
        assert not os.path.exists(out)

    def test_multiwidget_checkbox_with_differing_on_states(self, tmp_dir):
        # Review: two widget kids of ONE checkbox with different on-state
        # names ("Yes"/"On") must BOTH light when checked.
        src = os.path.join(tmp_dir, "mw.pdf")
        pdf = pikepdf.new()
        page = pdf.add_blank_page(page_size=(300, 300))

        def state_ap(on_name):
            n = Dictionary()
            on_stream = pdf.make_stream(b"q Q")
            off_stream = pdf.make_stream(b"q Q")
            n[Name("/" + on_name)] = on_stream
            n[Name("/Off")] = off_stream
            return Dictionary(N=n)

        k1 = pdf.make_indirect(
            Dictionary(Type=Name.Annot, Subtype=Name.Widget, Rect=[40, 200, 56, 216], AP=state_ap("Yes"))
        )
        k2 = pdf.make_indirect(
            Dictionary(Type=Name.Annot, Subtype=Name.Widget, Rect=[40, 160, 56, 176], AP=state_ap("On"))
        )
        parent = pdf.make_indirect(
            Dictionary(T=pikepdf.String("dual"), FT=Name.Btn, Kids=pikepdf.Array([k1, k2]))
        )
        k1["/Parent"] = parent
        k2["/Parent"] = parent
        page.obj["/Annots"] = pikepdf.Array([k1, k2])
        pdf.Root["/AcroForm"] = pdf.make_indirect(Dictionary(Fields=pikepdf.Array([parent])))
        pdf.save(src)
        pdf.close()

        out = os.path.join(tmp_dir, "out.pdf")
        fill_form_fields(src, out, {"dual": True})
        with pikepdf.open(out) as pdf2:
            annots = pdf2.pages[0].obj["/Annots"]
            states = sorted(str(a["/AS"]) for a in annots)
            assert states == ["/On", "/Yes"]  # each widget lit via ITS state

        out2 = os.path.join(tmp_dir, "out2.pdf")
        fill_form_fields(src, out2, {"dual": False})
        with pikepdf.open(out2) as pdf2:
            assert all(str(a["/AS"]) == "/Off" for a in pdf2.pages[0].obj["/Annots"])

    def test_bare_widget_kid_with_stray_ft_not_duplicated(self, tmp_dir):
        # Review: a /T-less kid carrying its own /FT must be treated as a
        # WIDGET of the parent, never a duplicate field that shadows siblings
        # in the fill's name->field map.
        src = os.path.join(tmp_dir, "stray.pdf")
        pdf = pikepdf.new()
        page = pdf.add_blank_page(page_size=(300, 300))
        named_kid = pdf.make_indirect(
            Dictionary(Type=Name.Annot, Subtype=Name.Widget, Rect=[40, 200, 200, 224],
                       T=pikepdf.String("inner"), FT=Name.Tx)
        )
        bare1 = pdf.make_indirect(
            Dictionary(Type=Name.Annot, Subtype=Name.Widget, Rect=[40, 160, 200, 184], FT=Name.Tx)
        )
        bare2 = pdf.make_indirect(
            Dictionary(Type=Name.Annot, Subtype=Name.Widget, Rect=[40, 120, 200, 144], FT=Name.Tx)
        )
        parent = pdf.make_indirect(
            Dictionary(T=pikepdf.String("grp"), FT=Name.Tx,
                       Kids=pikepdf.Array([named_kid, bare1, bare2]))
        )
        for k in (named_kid, bare1, bare2):
            k["/Parent"] = parent
        page.obj["/Annots"] = pikepdf.Array([named_kid, bare1, bare2])
        pdf.Root["/AcroForm"] = pdf.make_indirect(
            Dictionary(Fields=pikepdf.Array([parent]), DA=pikepdf.String("/Helv 10 Tf 0 g"))
        )
        pdf.save(src)
        pdf.close()

        names = [f["name"] for f in read_form_fields(src)["fields"]]
        assert names.count("grp") == 1 and "grp.inner" in names  # no duplicates
        out = os.path.join(tmp_dir, "out.pdf")
        fill_form_fields(src, out, {"grp": "both widgets"})
        with pikepdf.open(out) as pdf2:
            annots = pdf2.pages[0].obj["/Annots"]
            with_value = [
                a for a in annots
                if a.get("/AP") is not None
                and isinstance(a["/AP"].get("/N"), pikepdf.Stream)
                and b"both widgets" in a["/AP"]["/N"].read_bytes()
            ]
            assert len(with_value) == 2  # BOTH bare widgets got the appearance
